// ============================================
// USER MODE CODE
// ============================================
PROCEDURE user_program()
BEGIN
  PRINT "Starting file read..."

  // Library function call (looks like normal function)
  result = read(file_descriptor, buffer, 1024)

  // Continue after system call returns
  IF result > 0 THEN
    PRINT "Read successful"
  ENDIF
END

// ============================================
// KERNEL MODE (Simplified)
// ============================================
PROCEDURE kernel_read(fd, buffer, size)
BEGIN
  // Verify file descriptor is valid
  process = GET_CURRENT_PROCESS()
  file = process.file_table[fd]

  IF file = NULL THEN
    RETURN -EBADF
  ENDIF

  // Check file permissions for reading
  IF NOT can_read(file) THEN
    RETURN -EACCES
  ENDIF

  // Perform actual read (interacts with storage device)
  data = DEVICE_READ(file.inode, position)
  COPY_TO_USER(buffer, data)

  RETURN bytes_read
END

// ============================================
// TRAP HANDLER (CPU Interrupt Handler)
// ============================================
PROCEDURE handle_system_call(syscall_number, params)
BEGIN
  // Save current CPU state
  SAVE_CPU_STATE()

  // Switch to kernel privilege level
  SET_CPU_MODE(KERNEL_PRIVILEGE)

  // Dispatch to appropriate system call handler
  SELECT syscall_number
    CASE SYS_read: result = kernel_read(params)
    CASE SYS_write: result = kernel_write(params)
    CASE SYS_open: result = kernel_open(params)
    // ... other system calls
  ENDSELECT

  // Restore user mode
  SET_CPU_MODE(USER_PRIVILEGE)
  RESTORE_CPU_STATE()

  RETURN result to user program
END

// ============================================
// KERNEL MODULE CODE (Example: Simple Character Device)
// ============================================

// Module initialization - called when module is loaded
FUNCTION module_init() RETURNS integer
BEGIN
  PRINT "Loading custom kernel module..."

  // Register device with kernel
  major_number = register_chrdev(MAJOR_NUMBER, "my_device", &file_ops)
  IF major_number < 0 THEN
    PRINT "Failed to register device"
    RETURN major_number
  ENDIF

  // Initialize device data
  device_data = allocate_memory(sizeof(device_struct))

  PRINT "Module loaded successfully with major number: ", major_number
  RETURN 0  // Success
END

// Module cleanup - called when module is unloaded
FUNCTION module_exit()
BEGIN
  PRINT "Unloading kernel module..."

  // Unregister device
  unregister_chrdev(major_number, "my_device")

  // Free allocated memory
  free_memory(device_data)

  PRINT "Module unloaded successfully"
END

// File operations handler
FUNCTION device_read(file, buffer, count, offset)
BEGIN
  // Copy data from kernel space to user space
  copy_to_user(buffer, kernel_data, count)
  RETURN bytes_copied
END

// Module metadata
MODULE_LICENSE("GPL")
MODULE_AUTHOR("Example Author")
MODULE_DESCRIPTION("Sample Loadable Kernel Module")

// Entry and exit points (macros in actual C code)
REGISTER_INIT(module_init)
REGISTER_EXIT(module_exit)
